function makeWalkGpx(walk) { const trace = walk?.trace || []; const points = trace.map(point => `      <trkpt lat="${point.lat}" lon="${point.lon}"><time>${new Date(point.t || Date.now()).toISOString()}</time></trkpt>`).join('\n'); return `<?xml version="1.0" encoding="UTF-8"?>\n<gpx version="1.1" creator="MapPi3 ${VERSION}" xmlns="http://www.topografix.com/GPX/1/1">\n  <metadata><name>${walk?.name || 'MapPi3 saved walk'}</name></metadata>\n  <trk><name>${walk?.name || 'MapPi3 saved walk'}</name><trkseg>\n${points}\n  </trkseg></trk>\n</gpx>\n`; }
function makeGpx() { const points = plannerWaypoints.map(p => `    <wpt lat="${p.lat}" lon="${p.lon}"><name>${p.name}</name><type>${p.type}</type></wpt>`).join('\n'); const rtepts = plannerWaypoints.map(p => `      <rtept lat="${p.lat}" lon="${p.lon}"><name>${p.name}</name></rtept>`).join('\n'); return `<?xml version="1.0" encoding="UTF-8"?>\n<gpx version="1.1" creator="MapPi3 ${VERSION}" xmlns="http://www.topografix.com/GPX/1/1">\n  <metadata><name>${primaryRoutePack.name} - MapPi3 Sample</name></metadata>\n${points}\n  <rte><name>${primaryRoutePack.name}</name>\n${rtepts}\n  </rte>\n</gpx>\n`; }
