function Settings({ settings, setSettings, clearLocalState }) { const update = (key, value) => setSettings(s => ({ ...s, [key]: value })); return <section className="panel two-col"><div><h2>Settings</h2><div className="setting-row"><span>Connection mode</span><select value={settings.mode} onChange={e => update('mode', e.target.value)}><option>Hotspot</option><option>Known Wi‑Fi</option><option>Offline only</option></select></div><div className="setting-row"><span>Units</span><select value={settings.units} onChange={e => update('units', e.target.value)}><option>Miles / °F</option><option>Kilometers / °C</option></select></div><button className="ghost full" onClick={clearLocalState}>Reset local {VERSION} state</button></div><div><h2>Location stack</h2><p className="muted">Current default: {localHome.label}. Live phone GPS requires a secure browser context; raw HTTP IP previews are limited.</p></div></section>; }
