function ActiveTab(props) { if (props.activeTab === 'Explore') return <Explore routes={props.routes} onDownload={props.onDownload} searchQuery={props.searchQuery} selectedRoute={props.selectedRoute} setSelectedRoute={props.setSelectedRoute} onStartRoute={props.onStartRoute} onExportRouteGpx={props.onExportRouteGpx} />; if (props.activeTab === 'Plan') return <Plan gpxStatus={props.gpxStatus} onExportGpx={props.onExportGpx} onImportGpx={props.onImportGpx} />; if (props.activeTab === 'Navigate') return <Navigate recording={props.recording} setRecording={props.setRecording} elapsed={props.elapsed} progress={props.progress} setProgress={props.setProgress} resetTrack={props.resetTrack} selectedRoute={props.selectedRoute} />; if (props.activeTab === 'Daily Exercise') return <DailyExercise walk={props.walk} setWalk={props.setWalk} conditions={props.conditions} savedWalks={props.savedWalks} setSavedWalks={props.setSavedWalks} onExportWalkGpx={props.onExportWalkGpx} onDeleteWalk={props.onDeleteWalk} />; if (props.activeTab === 'Saved') return <Saved routes={props.routes} savedWalks={props.savedWalks} onExportWalkGpx={props.onExportWalkGpx} onDeleteWalk={props.onDeleteWalk} />; if (props.activeTab === 'Health') return <Health hiker={props.hiker} setHiker={props.setHiker} conditions={props.conditions} setConditions={props.setConditions} elapsed={props.elapsed} progress={props.progress} healthHistory={props.healthHistory} setHealthHistory={props.setHealthHistory} />; if (props.activeTab === 'Field Kit') return <FieldKit />; if (props.activeTab === 'Survival') return <Survival />; return <Settings settings={props.settings} setSettings={props.setSettings} clearLocalState={props.clearLocalState} />; }

function App() {
  const [activeTab, setActiveTab] = useState(() => loadStored('mappi3.activeTab', 'Explore'));
  const touchStartX = useRef(null);
  const [searchQuery, setSearchQuery] = useState(() => loadStored('mappi3.searchQuery', ''));
  const [settings, setSettings] = useState(() => loadStored('mappi3.settings', { mode: 'Hotspot', units: 'Miles / °F', theme: 'Topo Night' }));
  const [hiker, setHiker] = useState(() => ({ ...defaultHiker, ...loadStored('mappi3.hiker', {}) }));
  const [conditions, setConditions] = useState(() => ({ ...defaultConditions, ...loadStored('mappi3.conditions', {}) }));
  const [routes, setRoutes] = useState(() => { const stored = loadStored('mappi3.routes', null); if (!stored) return seedRoutes; const storedById = Object.fromEntries(stored.map(route => [route.id, route])); return seedRoutes.map(route => ({ ...route, status: storedById[route.id]?.status ?? route.status, tags: storedById[route.id]?.tags ?? route.tags })); });
  const [healthHistory, setHealthHistory] = useState(() => loadStored('mappi3.healthHistory', [])); const [selectedRouteId, setSelectedRouteId] = useState(() => loadStored('mappi3.selectedRouteId', seedRoutes[0]?.id)); const selectedRoute = useMemo(() => routes.find(route => route.id === selectedRouteId) || routes[0], [routes, selectedRouteId]); const [recording, setRecording] = useState(false); const [elapsed, setElapsed] = useState(() => loadStored('mappi3.elapsed', 0)); const [progress, setProgress] = useState(() => loadStored('mappi3.progress', 0.34)); const [walk, setWalk] = useState(() => loadStored('mappi3.walk', { active: false, trace: [], ticks: 0, startedAt: null, endedAt: null, source: 'not started' })); const [savedWalks, setSavedWalks] = useState(() => loadStored('mappi3.walkHistory', [])); const [gpxStatus, setGpxStatus] = useState('GPX tools ready. Export downloads a sample route file; import stages a mock uploaded GPX.');
  const filteredRoutes = useMemo(() => routes.filter(route => routeMatches(route, searchQuery)), [routes, searchQuery]); const downloadedCount = useMemo(() => routes.filter(r => r.status === 'Downloaded').length, [routes]); const healthMetrics = useMemo(() => calcHealth({ hiker, conditions, elapsed, progress }), [hiker, conditions, elapsed, progress]);
  useEffect(() => localStorage.setItem('mappi3.activeTab', JSON.stringify(activeTab)), [activeTab]); useEffect(() => localStorage.setItem('mappi3.healthHistory', JSON.stringify(healthHistory)), [healthHistory]); useEffect(() => localStorage.setItem('mappi3.selectedRouteId', JSON.stringify(selectedRouteId)), [selectedRouteId]); useEffect(() => localStorage.setItem('mappi3.searchQuery', JSON.stringify(searchQuery)), [searchQuery]); useEffect(() => localStorage.setItem('mappi3.settings', JSON.stringify(settings)), [settings]); useEffect(() => localStorage.setItem('mappi3.routes', JSON.stringify(routes)), [routes]); useEffect(() => localStorage.setItem('mappi3.elapsed', JSON.stringify(elapsed)), [elapsed]); useEffect(() => localStorage.setItem('mappi3.progress', JSON.stringify(progress)), [progress]); useEffect(() => localStorage.setItem('mappi3.hiker', JSON.stringify(hiker)), [hiker]); useEffect(() => localStorage.setItem('mappi3.conditions', JSON.stringify(conditions)), [conditions]); useEffect(() => localStorage.setItem('mappi3.walk', JSON.stringify({ ...walk, active: false })), [walk]); useEffect(() => localStorage.setItem('mappi3.walkHistory', JSON.stringify(savedWalks)), [savedWalks]);
  useEffect(() => { if (!recording) return undefined; const timer = setInterval(() => { setElapsed(e => e + 1); setProgress(p => (p >= 0.98 ? 0.02 : Math.min(0.99, p + 0.012))); }, 1000); return () => clearInterval(timer); }, [recording]);
  useEffect(() => {
    let cancelled = false;
    async function loadWeather() {
      try {
        const forecastUrl = `https://api.open-meteo.com/v1/forecast?latitude=${localHome.lat}&longitude=${localHome.lon}&current=temperature_2m,relative_humidity_2m&temperature_unit=fahrenheit&timezone=auto`;
        const airUrl = `https://air-quality-api.open-meteo.com/v1/air-quality?latitude=${localHome.lat}&longitude=${localHome.lon}&current=us_aqi`;
        const [forecast, air] = await Promise.all([fetch(forecastUrl).then(r => r.json()), fetch(airUrl).then(r => r.json()).catch(() => null)]);
        if (cancelled) return;
        setConditions(c => ({
          ...c,
          source: 'Open-Meteo live',
          location: localHome.label,
          tempF: Math.round(forecast?.current?.temperature_2m ?? c.tempF),
          humidity: Math.round(forecast?.current?.relative_humidity_2m ?? c.humidity),
          airQuality: Math.round(air?.current?.us_aqi ?? c.airQuality),
          elevationFt: c.elevationFt || 203
        }));
      } catch {
        if (!cancelled) setConditions(c => ({ ...c, source: 'Local fallback' }));
      }
    }
    loadWeather();
    return () => { cancelled = true; };
  }, []);
  const onDownload = (id) => setRoutes(rs => rs.map(route => route.id === id ? { ...route, status: 'Downloaded', tags: Array.from(new Set([...route.tags, 'downloaded'])) } : route)); const onStartRoute = (route) => { setSelectedRouteId(route.id); setProgress(0); setElapsed(0); setRecording(true); setActiveTab('Navigate'); }; const resetTrack = () => { setRecording(false); setElapsed(0); setProgress(0); };
  const onExportGpx = () => { downloadTextFile('mappi3-sample-route.gpx', makeGpx(), 'application/gpx+xml'); setGpxStatus(`Exported mappi3-sample-route.gpx from ${primaryRoutePack.name}.`); }; const onExportRouteGpx = (route) => downloadTextFile(`${(route.name || 'mappi3-route').toLowerCase().replace(/[^a-z0-9]+/g, '-')}.gpx`, makeRouteGpx(route), 'application/gpx+xml'); const onExportWalkGpx = (item) => downloadTextFile(`${(item.name || 'mappi3-walk').toLowerCase().replace(/[^a-z0-9]+/g, '-')}.gpx`, makeWalkGpx(item), 'application/gpx+xml'); const onDeleteWalk = (id) => setSavedWalks(items => items.filter(item => (item.id || item.savedAt) !== id)); const onImportGpx = () => setGpxStatus('Mock import staged: sample GPX would be parsed into route geometry, waypoints, POIs, and an offline pack request.'); const clearLocalState = () => { ['mappi3.activeTab','mappi3.selectedRouteId','mappi3.searchQuery','mappi3.settings','mappi3.routes','mappi3.elapsed','mappi3.progress','mappi3.hiker','mappi3.healthHistory','mappi3.conditions','mappi3.walk','mappi3.walkHistory'].forEach(k => localStorage.removeItem(k)); location.reload(); }; const goTab = (delta) => { const index = tabs.indexOf(activeTab); setActiveTab(tabs[(index + delta + tabs.length) % tabs.length]); }; const onTouchStart = (event) => { if (event.target.closest('input, textarea, select, button, .leaflet-container')) return; touchStartX.current = event.touches[0].clientX; }; const onTouchEnd = (event) => { if (touchStartX.current === null) return; const dx = event.changedTouches[0].clientX - touchStartX.current; touchStartX.current = null; if (Math.abs(dx) > 70) goTab(dx < 0 ? 1 : -1); };
  return <main className="app-shell" onTouchStart={onTouchStart} onTouchEnd={onTouchEnd}><section className="hero-card"><div className="top-line"><span className="brand-mark">△</span><div><h1>MapPi3</h1><p>Trail OS · {VERSION}</p></div><Pill tone="online">{settings.mode}</Pill></div><div className="search-box"><span>⌕</span><input placeholder="Search places, trails, foods, water, saved GPX…" value={searchQuery} onChange={e => { setSearchQuery(e.target.value); setActiveTab('Explore'); }} /><button className="ghost small" onClick={() => setSearchQuery('')}>Clear</button></div><div className="search-hint">{searchQuery ? `${filteredRoutes.length} route match(es). Route search is active. Food/drink custom entry lives in Health.` : 'Swipe left/right anywhere outside controls to change pages.'}</div><div className="quick-stats"><Stat value={(progress * primaryRoutePack.distanceMiles).toFixed(1)} label="hike mi" /><Stat value={formatClock(elapsed)} label="elapsed" /><Stat value={Math.round(healthMetrics.caloriesBurned)} label="cal burned" /><Stat value={`${downloadedCount}/3`} label="packs local" /></div></section><section className="tabs-grid" aria-label="MapPi3 sections">{tabs.map(item => <button key={item} className={item === activeTab ? 'active' : ''} onClick={() => setActiveTab(item)}>{item}</button>)}</section><ActiveTab activeTab={activeTab} routes={filteredRoutes} searchQuery={searchQuery} selectedRoute={selectedRoute} setSelectedRoute={(route) => setSelectedRouteId(route?.id)} onStartRoute={onStartRoute} onExportRouteGpx={onExportRouteGpx} onDownload={onDownload} settings={settings} setSettings={setSettings} recording={recording} setRecording={setRecording} elapsed={elapsed} progress={progress} setProgress={setProgress} resetTrack={resetTrack} gpxStatus={gpxStatus} onExportGpx={onExportGpx} onImportGpx={onImportGpx} clearLocalState={clearLocalState} hiker={hiker} setHiker={setHiker} healthHistory={healthHistory} setHealthHistory={setHealthHistory} conditions={conditions} setConditions={setConditions} walk={walk} setWalk={setWalk} savedWalks={savedWalks} setSavedWalks={setSavedWalks} onExportWalkGpx={onExportWalkGpx} onDeleteWalk={onDeleteWalk} /></main>;
}
createRoot(document.getElementById('root')).render(<App />);
